import React, { FC, useCallback, useEffect, useMemo, useRef, useState } from 'react';
import { connect } from 'react-redux';
import { Dispatch, bindActionCreators } from 'redux';
import { useFocusEffect } from '@react-navigation/native';
import { eventSelectContent, eventScreenViewV3, eventModalView } from '~/constants/functions';
import ApiError from '../../atomic/organisms/ApiError';
import BasicScreen from '../../atomic/templates/BasicScreen';
import { PointsActions } from '../../redux/ducks/points';
import { AppReducers } from '../../redux/reducers/Models';
import { PointsProps } from './Models';
import PointsView from './view';
import { useCardBuilderWhereUseMyPoints } from '../../hooks/custom/useCardBuilderWhereUseMyPoints';
import { PropsModalizeRef } from '@semparar/design-system-app/src/@types/modelize';
import { getParameterPointsProgram } from '../../newArch/store/rewardProgram';

const Points: FC<PointsProps> = ({
  navigation,
  requestPointsBalance,
  requestPointsProducts,
  requestInitialData,
  clear,
  pointsReducer,
}) => {
  const hasFocused = useRef(false);
  const modalizeRef = useRef<PropsModalizeRef>(null as unknown as PropsModalizeRef);
  const [isMyOrders, setIsMyOrders] = useState(false);

  const handleMyOrders = () => {
    navigation.navigate('MyOrdersRewardProgram')
  }

  const handleGoBack = () => {
    navigation.goBack();
  };
  const handlerGoHome = () => {
    navigation.navigate('Home');
  };

  const handleOpenDefault = () => {
    eventSelectContent({
      content_type: 'cta',
      content_id: 'informacao_pontos',
      location_1: 'monetizacao',
      location_2: 'hub_recompensas_spmais',
      location_3: 'home_hub_recompensas',
    });

    modalizeRef.current?.open?.();
  };

  const handleOpenMyOrders = () => {
    setIsMyOrders(true);

    eventModalView({
      content_id: 'menu_header',
      location_1: 'monetizacao',
      location_2: 'hub_recompensas_spmais',
      location_3: 'home_hub_recompensas',
    });
  };

  const buildPointsCardItems = useCardBuilderWhereUseMyPoints();

  const requestPointsCallback = useCallback(() => {
    requestPointsBalance();
    requestPointsProducts();
    getParameterPointsProgram();
  }, [requestPointsBalance, requestPointsProducts]);

  const handleApiErrorPress = () => {
    if (pointsReducer.isErrorBalance || pointsReducer.isErrorProducts) {
      requestPointsCallback();
    }
  };

  useFocusEffect(
    useCallback(() => {
      if (!hasFocused.current) {
        eventScreenViewV3('home_hub_recompensas', 'hub_recompensas_spmais', 'monetizacao', {
          location_1: 'monetizacao',
          location_2: 'hub_recompensas_spmais',
          location_3: 'home_hub_recompensas',
        });
        hasFocused.current = true;
      }
      return () => {
        hasFocused.current = false;
      };
    }, [])
  );

  useEffect(() => {
    requestInitialData();
    getParameterPointsProgram();

    return () => {
      clear();
    };
  }, []);

  useFocusEffect(
    useCallback(() => {
      requestPointsCallback();
      return undefined;
    }, [requestPointsCallback])
  );

  const view = useMemo(() => {
    if (pointsReducer.isErrorProducts || pointsReducer.isErrorBalance) {
      return (
        <BasicScreen
          leftIconOnPress={handleGoBack}
          title="Programa de Pontos"
          errorButtonOnPress={handleApiErrorPress}
        >
          <ApiError onPress={handleApiErrorPress} />
        </BasicScreen>
      );
    }

    const normalizedItems = buildPointsCardItems(pointsReducer.products);

    const onOpenExtract = () => {
      eventSelectContent({
        content_type: 'cta',
        content_id: 'exibir_extrato',
        location_1: 'monetizacao',
        location_2: 'hub_recompensas_spmais',
        location_3: 'home_hub_recompensas',
      });
      navigation.navigate('ExtractRewardProgram', {
        analytics: {
          screen_name: 'extrato_hub_recompensas',
          screen_class: 'hub_recompensas_spmais',
          screen_bussines: 'monetizacao',
          screen_info: {
            location_1: 'monetizacao',
            location_2: 'hub_recompensas_spmais',
            location_3: 'extrato_hub_recompensas',
          },
        },
      });
    };

    return (
      <PointsView
        items={normalizedItems}
        isLoadingBalance={pointsReducer.isLoadingBalance}
        handleGoBack={handleGoBack}
        pointsAvailable={pointsReducer.points}
        pointsOptions={pointsReducer.products}
        onOpenExtract={onOpenExtract}
        onOpenDefault={handleOpenDefault}
        modalizeRef={modalizeRef}
        isMyOrders={isMyOrders}
        setIsMyOrders={setIsMyOrders}
        handlerGoHome={handlerGoHome}
        onMenuPress={handleOpenMyOrders}
        handleMyOrders={handleMyOrders}
      />
    );
  }, [pointsReducer, navigation, buildPointsCardItems, isMyOrders]);

  return view;
};

export const mapStateToProps = ({ pointsReducer }: AppReducers) => ({
  pointsReducer,
});

export const mapDispatchToProps = (dispatch: Dispatch) => {
  return bindActionCreators(
    {
      ...PointsActions,
    },
    dispatch
  );
};

export default connect(mapStateToProps, mapDispatchToProps)(Points);
